previewCss:
.darma-loader-darma-custom-620 {color: var(--loader-color, #2563eb);
  --loader-secondary-color: var(--loader-secondary-color, #38bdf8);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 68px;
   aspect-ratio: 1;
   border: 8px solid currentColor;
   box-sizing: border-box;
   background: radial-gradient(farthest-side,currentColor 98%,#0000) 50%/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) 50%/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) 50%/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) 50%/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) 50%/80% 80%, currentColor;
   background-repeat: no-repeat;
   filter: blur(4px) contrast(10);
   animation: darma-loader-darma-custom-620-l17 1s infinite alternate;
}
@keyframes darma-loader-darma-custom-620-l17  {
  0% {background-position:50%,50%,50%,50%,50%,50%,50%}
25% {background-position:0 0,50%,50%,50%,50%,50%,50%}
50% {background-position:0 0,100% 0,50%,50%,50%,50%,50%}
75% {background-position:0 0,100% 0,100% 100%,50%,50%,50%,50%}
100% {background-position:0 0,100% 0,100% 100%,0 100%,50%,50%,50%}
}

